    if (k == 0) return 0;
    if (k == 1) {
        // Count numbers with binary representation of 1 bit (i.e., powers of 2)
        long long count = 0;
        long long power = 1;
        while (power <= n) {
            count++;
            power <<= 1;
        }
        return count;
    }

