    // Since k is small (<=5), we can use BFS to find the depth
    // We use a queue to perform BFS starting from numbers with popcount 1
    // Each node is a number, and its depth is the number of steps to reach 1

    // We use a visited array to keep track of the depth of each number
    // Since n can be up to 1e15, we can't use an array, so we use a map
    // We use a queue to perform BFS
    // We use a map to store the depth of each number

    map<long long, long long> depth;
    queue<long long> q;

    // Start with numbers that have popcount 1 (i.e., powers of 2)
    long long power = 1;
    while (power <= n) {
        q.push(power);
        depth[power] = 1;
        power <<= 1;
    }

    // Perform BFS
    while (!q.empty()) {
        long long current = q.front();
        q.pop();

        long long popcount = __builtin_popcount(current);
        long long next = popcount;

        if (depth.find(next) == depth.end()) {
            depth[next] = depth[current] + 1;
            q.push(next);
        }
    }

    // Count numbers with depth exactly k
    long long count = 0;
    for (long long i = 1; i <= n; ++i) {
        if (depth.find(i) != depth.end() && depth[i] == k) {
            count++;
        }
    }

    return count;
}

